scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		var strInputSchema = x_snc_devtools.GetStringValue(current.input_schema);

		var input_schema = x_snc_devtools.ParseJson(strInputSchema);
		if (x_snc_devtools.IsArray(input_schema) == false)
		{
			engine.finding.increment();
		}
	}

})(engine);
